class Solution:
    def minimumOperations(self, nums, start, goal):
        dist = {start: 0}
        frontier = [start]
        while frontier:
            nxt_frontier = []
            for x in frontier:
                for v in nums:
                    for y in (x + v, x - v, x ^ v):
                        if 0 <= y <= 1000 and y not in dist:
                            dist[y] = dist[x] + 1
                            nxt_frontier.append(y)
            frontier = nxt_frontier
        best = None
        for x, d in dist.items():
            for v in nums:
                for y in (x + v, x - v, x ^ v):
                    if y == goal:
                        if best is None or d + 1 < best:
                            best = d + 1
        return best if best is not None else -1

