from collections import deque


class Solution:
    def minimumOperations(self, nums, start, goal):
        if start == goal:
            return 0
        visited = [False] * 1001
        visited[start] = True
        q = deque([start])
        steps = 0
        while q:
            steps += 1
            for _ in range(len(q)):
                x = q.popleft()
                for v in nums:
                    for nxt in (x + v, x - v, x ^ v):
                        if nxt == goal:
                            return steps
                        if 0 <= nxt <= 1000 and not visited[nxt]:
                            visited[nxt] = True
                            q.append(nxt)
        return -1

