var minimumOperations = function(nums, start, goal) {
    if (start === goal) return 0;
    const visited = new Array(1001).fill(false);
    visited[start] = true;
    let queue = [start];
    let steps = 0;
    while (queue.length) {
        steps++;
        const next = [];
        for (const x of queue) {
            for (const v of nums) {
                for (const nxt of [x + v, x - v, x ^ v]) {
                    if (nxt === goal) return steps;
                    if (nxt >= 0 && nxt <= 1000 && !visited[nxt]) {
                        visited[nxt] = true;
                        next.push(nxt);
                    }
                }
            }
        }
        queue = next;
    }
    return -1;
};
